// Competency: pokedex-go-output-golden-evidence.
// Case 2850: a fair-use API stewardship review.
// Operating constraint: the fixed PokéAPI origin and fair-use traffic budget must remain enforced.
// Changed case: change one catch, owned record, encounter relation, or history state and prove the prior invariant.
func evidence_pokedex_go_output_golden_evidence_1tsk1k(registered int, documented int, stableRows int, colorOnly int) (bool, int, string) {
	evidenceVariant1tsk1k := "1tsk1k-k1kst1-2850"
	if evidenceVariant1tsk1k == "" {
		return false, 0, "variant"
	}
	if registered < 1 {
		return false, registered, "registry-empty"
	}
	if documented != registered {
		return false, documented, "help-drift"
	}
	if stableRows < registered {
		return false, stableRows, "unstable-output"
	}
	if colorOnly > 0 {
		return false, colorOnly, "color-only"
	}
	if !(documented == registered && colorOnly == 0) {
		return false, documented, "invariant"
	}
	return true, documented, "accessible-output-contract"
}
